SELECT ?game ?attendance WHERE {
  ?game wdt:P31 wd:Q40993 ;
        wdt:P1545 ?series ;
        wdt:P171 wd:Q225387 ;
        wdt:P217 wd:Q578848 ;
        wdt:P8598 ?attendance .
  ?series wdt:P1667 wd:Q11274391 ;
          wdt:P585 ?eventDate .
  FILTER (YEAR(?eventDate) >= 1972 && YEAR(?eventDate) <= 1979)
}
ORDER BY DESC(?attendance)
LIMIT 5

